import asyncio
import websockets
import json
from collections import defaultdict

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory = {}

    def add_item(self, item, quantity):
        if item in self.inventory:
            self.inventory[item] += quantity
        else:
            self.inventory[item] = quantity

    def remove_item(self, item, quantity):
        if item in self.inventory and self.inventory[item] >= quantity:
            self.inventory[item] -= quantity
            if self.inventory[item] == 0:
                del self.inventory[item]
            return True
        return False

class GameServer:
    def __init__(self):
        self.players = {}
        self.connected = set()

    async def register(self, websocket):
        self.connected.add(websocket)

    async def unregister(self, websocket):
        self.connected.remove(websocket)
        username = self.get_username(websocket)
        if username:
            del self.players[username]

    async def handle_message(self, websocket, message):
        data = json.loads(message)
        action = data['action']
        username = data['username']

        if action == 'connect':
            self.players[username] = Player(username)
            await websocket.send(json.dumps({'status': 'connected', 'username': username}))

        elif action == 'add_item':
            item = data['item']
            quantity = data['quantity']
            self.players[username].add_item(item, quantity)
            await websocket.send(json.dumps({'status': 'item_added', 'item': item, 'quantity': quantity}))

        elif action == 'trade':
            target_username = data['target_username']
            item = data['item']
            quantity = data['quantity']
            if self.players[username].remove_item(item, quantity):
                self.players[target_username].add_item(item, quantity)
                await websocket.send(json.dumps({'status': 'trade_success', 'item': item, 'quantity': quantity}))
                target_ws = self.get_websocket_by_username(target_username)
                if target_ws:
                    await target_ws.send(json.dumps({'status': 'item_received', 'item': item, 'quantity': quantity}))
            else:
                await websocket.send(json.dumps({'status': 'trade_failed', 'message': 'Not enough items'}))

    def get_username(self, websocket):
        for username, player in self.players.items():
            if player.websocket == websocket:
                return username
        return None

    def get_websocket_by_username(self, username):
        for ws in self.connected:
            if self.get_username(ws) == username:
                return ws
        return None

    async def main_loop(self, websocket, path):
        await self.register(websocket)
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        finally:
            await self.unregister(websocket)

    def run(self):
        start_server = websockets.serve(self.main_loop, 'localhost', 6789)
        asyncio.get_event_loop().run_until_complete(start_server)
        asyncio.get_event_loop().run_forever()

if __name__ == '__main__':
    server = GameServer()
    server.run()